import tarfile
import os


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        # Create destination directory if it doesn't exist
        os.makedirs(dest_path, exist_ok=True)

        # Open and extract tar file with security checks
        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                # Skip absolute paths and paths containing '..' to prevent directory traversal
                if os.path.isabs(member.name) or ".." in member.name.split("/"):
                    continue

                # Skip symlinks to prevent potential security issues
                if member.issym() or member.islnk():
                    continue

                # Extract the member safely
                tar.extract(member, dest_path)

        return True
    except (tarfile.TarError, OSError, IOError):
        return False

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def evaluate(node):
        if isinstance(node, ast.Num):  # For Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # For Python >= 3.8
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Only numeric constants are allowed")
        elif isinstance(node, ast.BinOp):
            if type(node.op) in operators:
                left = evaluate(node.left)
                right = evaluate(node.right)
                return operators[type(node.op)](left, right)
            else:
                raise ValueError("Operator not allowed")
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in operators:
                operand = evaluate(node.operand)
                return operators[type(node.op)](operand)
            else:
                raise ValueError("Unary operator not allowed")
        elif isinstance(node, ast.Expression):
            return evaluate(node.body)
        else:
            raise ValueError("Invalid expression")

    try:
        # Parse the expression
        parsed = ast.parse(expr, mode='eval')
        # Evaluate safely
        result = evaluate(parsed)
        return str(result)
    except Exception:
        return ""

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    # Define valid info types and their corresponding header keys
    INFO_TYPE_MAPPING = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }

    # Validate inputs
    if not isinstance(info_type, str) or not isinstance(info_content, str):
        return header

    if not isinstance(header, dict):
        return header

    # Check if info_type is valid
    if info_type not in INFO_TYPE_MAPPING:
        return header

    # Sanitize info_content to prevent header injection
    # Remove newlines, carriage returns, and other control characters
    sanitized_content = ''.join(
        char for char in info_content 
        if char not in {'\n', '\r', '\x00', '\x0b', '\x0c'}
    )

    # Create a copy of the header to avoid modifying the original
    updated_header = header.copy()

    # Update the header
    updated_header[INFO_TYPE_MAPPING[info_type]] = sanitized_content

    return updated_header

import json
import yaml
from yaml import Loader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        # Read and parse the YAML file
        with open(yaml_file_path, 'r', encoding='utf-8') as file:
            try:
                yaml_data = yaml.load(file, Loader=Loader)
            except yaml.YAMLError as e:
                return f"Error: Invalid YAML content - {str(e)}"

        # Convert to JSON
        try:
            json_str = json.dumps(yaml_data, ensure_ascii=False)
            return json_str
        except (TypeError, ValueError) as e:
            return f"Error: Cannot convert to JSON - {str(e)}"

    except FileNotFoundError:
        return "Error: File not found"
    except Exception as e:
        return f"Error: {str(e)}"

