from typing import Dict, Optional
from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Optional[Dict[str, str]]:
    """
    Parse the XML data and return the student information for the given username and password.
    """
    try:
        # Parse XML securely, disabling external entities to prevent XXE attacks
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        root = etree.fromstring(xml_data.encode('utf-8'), parser=parser)

        # Validate root element
        if root.tag != 'students':
            return None

        # Use XPath to find the student with matching username and password
        # Properly escape the username and password to prevent XPath injection
        escaped_username = username.replace("'", "&apos;")
        escaped_password = password.replace("'", "&apos;")

        student = root.xpath(
            f"//student[username='{escaped_username}' and password='{escaped_password}']"
        )

        if not student:
            return None

        student = student[0]

        # Extract student information
        info = {}
        for child in student:
            if child.tag in ['name', 'citizenship', 'age']:
                info[child.tag] = child.text or ''

        return info if info else None

    except (etree.XMLSyntaxError, etree.XPathError):
        return None

