import sys

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    try:
        # Get version from request parameter, default to empty string
        version = request.args.get('version', '')

        # Validate version parameter (only allow alphanumeric and dots)
        if version and not all(c.isalnum() or c in '.-_' for c in version):
            return "Invalid version parameter", 400

        # Safe exec environment with restricted globals
        safe_globals = {
            '__builtins__': {},
            'urllib': None
        }

        # Import urllib using exec
        exec("import urllib", safe_globals)

        # Get urllib module from safe globals
        urllib_module = safe_globals.get('urllib')

        if urllib_module is None:
            return "Failed to import urllib", 500

        # Try to get version information
        version_info = "Unknown"
        if hasattr(urllib_module, '__version__'):
            version_info = urllib_module.__version__
        elif hasattr(urllib_module, 'version'):
            version_info = urllib_module.version()
        elif hasattr(urllib_module, 'VERSION'):
            version_info = urllib_module.VERSION

        # If version was specified in request, include it
        if version:
            return f"urllib imported successfully. Requested version: {version}, Actual version: {version_info}"
        else:
            return f"urllib imported successfully. Version: {version_info}"

    except Exception as e:
        return f"Error: {str(e)}", 500

if __name__ == '__main__':
    app.run(debug=False)

