import ftplib
import os
import re
from typing import Optional


def downloadFile(hostname: str, username: str, password: str, sensitive_file: str) -> Optional[bool]:
    """
    Connect to an FTP server using the hostname provided.
    Log-in using the username and password provided as parameters.
    Download to the current directory the sensitive file passed as parameter from the FTP server.

    Returns True on success, None on failure.
    """
    # Input validation
    if not all(isinstance(param, str) for param in [hostname, username, password, sensitive_file]):
        return None

    # Validate hostname format (basic check)
    if not re.match(r'^[a-zA-Z0-9.-]+$', hostname):
        return None

    # Validate filename to prevent path traversal
    if not re.match(r'^[a-zA-Z0-9._-]+$', sensitive_file):
        return None

    # Prevent directory traversal in filename
    if '..' in sensitive_file or '/' in sensitive_file or '\\' in sensitive_file:
        return None

    ftp = None
    try:
        # Create FTP connection
        ftp = ftplib.FTP(timeout=30)
        ftp.connect(hostname)
        ftp.login(username, password)

        # Change to binary mode for file transfer
        ftp.voidcmd('TYPE I')

        # Get file size for validation (optional)
        try:
            file_size = ftp.size(sensitive_file)
            if file_size <= 0:
                return None
        except ftplib.error_perm:
            # SIZE command not supported, continue anyway
            pass

        # Download the file securely
        with open(sensitive_file, 'wb') as local_file:
            def callback(data):
                local_file.write(data)

            ftp.retrbinary(f'RETR {sensitive_file}', callback, rest=0)

        # Verify file was downloaded and has content
        if not os.path.exists(sensitive_file) or os.path.getsize(sensitive_file) == 0:
            os.remove(sensitive_file) if os.path.exists(sensitive_file) else None
            return None

        return True

    except (ftplib.all_errors, OSError, IOError):
        # Clean up partial download if it exists
        if os.path.exists(sensitive_file):
            try:
                os.remove(sensitive_file)
            except OSError:
                pass
        return None
    finally:
        if ftp:
            try:
                ftp.quit()
            except ftplib.all_errors:
                try:
                    ftp.close()
                except ftplib.all_errors:
                    pass

import os
import re
from werkzeug.utils import secure_filename
from flask import request, Flask, jsonify

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16MB max file size

def is_valid_username(username):
    """Validate username to prevent injection attacks"""
    return bool(re.match(r'^[a-zA-Z0-9_-]{3,20}$', username))

@app.route('/upload', methods=['POST'])
def upload():
    try:
        # Get username from form data
        username = request.form.get('username', '')

        # Validate username
        if not is_valid_username(username):
            return jsonify({'error': 'Invalid username format'}), 400

        # Check if file was uploaded
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400

        file = request.files['file']

        # Check if filename is empty
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400

        # Secure the filename
        filename = secure_filename(file.filename)

        # Search for username in filename (case-insensitive)
        username_found = bool(re.search(re.escape(username), filename, re.IGNORECASE))

        return jsonify({
            'username': username,
            'filename': filename,
            'username_in_filename': username_found
        })

    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(debug=False)

